scwin.retrieveDetailYn;

scwin.onpageload = function() {

    const codeOptions = [
          { grpCd : "JA060", compID : "gr_results:ton,acb_eqNrmCd" }
        , { grpCd : "JA010", compID : "acb_bizTypCd" }
        , { grpCd : "JA080", compID : "acb_trfAdptCd" }
        , { grpCd : "JA090", compID : "acb_degClsCd" }
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.retrieveDetailYn = "notYet";

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        rd_useYn.setValue("1");

        $c.gus.cfDisableObjects([ed_prdyr, ed_vehclNo, ed_drcrNo, ed_degNm, ed_degForm
                               , acb_eqNrmCd, ed_stdFleffcncy, ed_clntNo_rslts, ed_clntNm_rslts 
                               , acb_bizTypCd, acb_trfAdptCd, ed_outBranch, ica_inspDt1, ica_inspDt2
                               , acb_degClsCd, ica_degDt, ica_firstRegDt, ica_chkDt
                               , ed_insrTrf, ica_cutShedDt, ica_insrTermFrom, ica_insrTermTo
                               , rd_useYn, ed_rmk 
        ]);

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// function name : scwin.f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
	ds_results.removeAll();
	ds_clnt.removeAll();
	ds_manager.removeAll();

    $c.sbm.execute(sbm_retrieve);

};

scwin.f_Retrieve_clntAndManager = function () {
	ds_cond_clntManager.set("eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
    $c.sbm.execute(sbm_retrieve_clntAndMngnr);    
};

//-------------------------------------------------------------------------
// function name : scwin.f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (){ 
	//저장을 무조건 타도록
	ds_results.setCellData(ds_results.getRowPosition(), "modDtm", "1");
	for(var i = 0 ; i < ds_results.getRowCount(); i++){
		if (ds_results.getRowStatus(i) == "C" || ds_results.getRowStatus(i) == "D" 
         || ds_results.getRowStatus(i) == "U" ){
			if (ds_results.getCellData(i, "vehclNo") == ""){
				await $c.win.alert("차량번호는 필수 입력 항목 입니다.");
				return false;
				break;
			}
			if (ds_results.getCellData(i, "ton") == ""){
				await $c.win.alert("차량번호 "+ds_results.getCellData(i, "vehclNo")+"의 톤은 필수 입력 항목 입니다.");
				return false;
				break
			}
			if (ds_results.getCellData(i, "clntNo") == ""){
				await $c.win.alert("차량번호 "+ds_results.getCellData(i, "vehclNo")+"의 소속거래처는 필수 입력 항목 입니다.");
				return false;
				break
			}
			if (ds_results.getCellData(i, "bizTypCd") == ""){
				await $c.win.alert("차량번호 "+ds_results.getCellData(i, "vehclNo")+"의 업종코드는 필수 입력 항목 입니다.");
				return false;
				break
			}
			if (ds_results.getCellData(i, "trfAdptCd") == ""){
				await $c.win.alert("차량번호 "+ds_results.getCellData(i, "vehclNo")+"의 요율적용코드는 필수 입력 항목 입니다.");
				return false;
				break
			}

			if (ds_results.getCellData(i, "useYn") == 1 && ds_manager.getRowCount() == 0){
				await $c.win.alert("매니저 정보를 입력해야 합니다.");
				return false;
			}
		}
	}

	for(var i = 0 ; i < ds_clnt.getRowCount(); i++){
		if (ds_clnt.getRowStatus(i) == "C" || ds_clnt.getRowStatus(i) == "D" 
         || ds_clnt.getRowStatus(i) == "U" ){
			if (ds_clnt.getCellData(i, "clntNo") == ""){
				await $c.win.alert("매출거래처는 필수 입력 항목 입니다.");
				return false;
				break;
			}
			if (ds_clnt.getCellData(i, "ctrtStDt") == ""){
				await $c.win.alert("매출거래처의 적용일자FROM은  필수 입력 항목 입니다.");
				return false;
				break;
			}
			if (ds_clnt.getCellData(i, "ctrtEndDt") == ""){
				await $c.win.alert("매출거래처의 적용일자TO는  필수 입력 항목 입니다.");
				return false;
				break;
			}
		}
	}

	for(var i = 0 ; i < ds_manager.getRowCount(); i++){
		if (ds_manager.getRowStatus(i) == "C" || ds_manager.getRowStatus(i) == "D" 
         || ds_manager.getRowStatus(i) == "U" ){
			if (ds_manager.getCellData(i, "clntNo") == ""){
				await $c.win.alert("매니저코드는 필수 입력 항목 입니다.");
				return false;
				break;
			}
			if (ds_manager.getCellData(i, "ctrtStDt") == ""){
				await $c.win.alert("매니저의 적용일자FROM은  필수 입력 항목 입니다.");
				return false;
				break;
			}
			if (ds_manager.getCellData(i, "ctrtEndDt") == ""){
				await $c.win.alert("매니저의 적용일자TO는  필수 입력 항목 입니다.");
				return false;
				break;
			}
		}
	}

	if (await $c.win.confirm(MSG_CM_CRM_001)){ //저장하시겠습니까?
        $c.sbm.execute(sbm_save);
	}		
};

//-------------------------------------------------------------------------
// function name : f_openPopUp
// function desc : popup
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch, row) {
	switch (disGubun) {
  		//조회조건 소속거래처
  		case 1:
		    var condition = "";
		    if (cbx_cnd_repClntYn.getValue() == "T"){
		    	condition = "RP";
		    }
            udc_clnt.setSelectId('retrieveSubsidaryClntList');
            udc_clnt.cfCommonPopUp(scwin.udc_clnt_callBackFunc	    // XML상의 SELECT ID
							      ,pCode							// 화면에서의 ??? Code Element의	Value
							      ,pName							// 화면에서의 ??? Name Element의	Value
							      ,pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
							      ,'5'							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
							      ,null							// Title순서
