//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// function name : scwin.f_goDriverPop
// function desc : 기사정보
// 20260227 버튼제외
//-------------------------------------------------------------------------
scwin.f_goDriverPop = async function () {
	var arrParam = new Array();
	var row = ds_manager.getRowPosition();
	if (ds_manager.getCellData(row, "clntNo") == ""){
		await $c.win.alert("등록된 매니저가 없습니다. 매니저를 먼저 등록하십시오.");
		return false;
	}

	// var pURL = "/ja/dn/basisinfomgnt/ja_010_01_03p.jsp?paramTitle=기사정보"
	// 		 + "&clntNo="+ds_manager.getCellData(row, "clntNo")
	// 		 + "&clntNm="+ds_manager.getCellData(row, "clntNm")
	// 		 ;
	// ref = window.showModalDialog(pURL,arrParam,"dialogWidth:530px; dialogHeight:580px");

    let win_url = "/ui/ja/dn/basisinfomgnt/ja_010_01_03p.xml";
    let data = {
          "clntNo"   : ds_manager.getCellData(row, "clntNo")
        , "clntNm"   : ds_manager.getCellData(row, "clntNm")
    };
    let opts = {
        id : "goDriverPop"
        , popupName : "기사정보"
        , modal : true
        , type : "browserPopup"
        , width : 840
        , height : 400
        , title : "기사정보"
    };
    await $c.win.openPopup(win_url, opts, data);
};


