scwin.f_newSetting = function () {
    ds_results.removeAll();
    var idx = ds_results.insertRow();
    ds_results.setRowPosition(idx);

    ds_results.setCellData(ds_results.getRowPosition(), "useYn", "1");
	ds_results.setCellData(ds_results.getRowPosition(), "coCd", "000"); //대성냉동 자회사 코드  003 -> 000

    ds_results.setCellData(ds_results.getRowPosition(), "stdFleffcncy", "0");
    ds_results.setCellData(ds_results.getRowPosition(), "insrTrf", "0");

    ds_clnt.removeAll();
    ds_manager.removeAll();

    $c.gus.cfEnableObjects([ed_prdyr, ed_vehclNo, ed_drcrNo, ed_degNm, ed_degForm, acb_eqNrmCd, ed_stdFleffcncy, ed_clntNo_rslts, ed_clntNm_rslts
					   ,acb_bizTypCd, acb_trfAdptCd, ed_outBranch, ica_inspDt1, ica_inspDt2, acb_degClsCd, ica_degDt, ica_firstRegDt, ica_chkDt
					   ,ed_insrTrf, ica_cutShedDt, ica_insrTermFrom, ica_insrTermTo, rd_useYn, ed_rmk]);
};

scwin.f_cancel = function (){
	ds_results.undoRow(ds_results.getRowPosition());
	ds_clnt.undoRow(ds_clnt.getRowPosition());
	ds_manager.undoRow(ds_manager.getRowPosition());
};

scwin.f_update = function (){
	$c.gus.cfEnableObjects([ed_prdyr, ed_vehclNo, ed_drcrNo, ed_degNm, ed_degForm, acb_eqNrmCd, ed_stdFleffcncy, ed_clntNo_rslts, ed_clntNm_rslts
					   ,acb_bizTypCd, acb_trfAdptCd, ed_outBranch, ica_inspDt1, ica_inspDt2, acb_degClsCd, ica_degDt, ica_firstRegDt, ica_chkDt
					   ,ed_insrTrf, ica_cutShedDt, ica_insrTermFrom, ica_insrTermTo, rd_useYn, ed_rmk]);
};

scwin.f_AddManager = async function (){
	if (ds_results.getRowCount() == 0){
		await $c.win.alert("차량정보가 없습니다. 신규버튼을 클릭하여 새로 등록하거나 조회하시기 바랍니다.");
	}else{
		if (scwin.retrieveDetailYn == "notYet"){
            ds_manager.removeAll();
		}else{
			var idx = ds_manager.insertRow();
            ds_manager.setRowPosition(idx);
		}

		ds_manager.setCellData(ds_manager.getRowPosition(), "selpchClsCd", "2"); //매입거래처
		ds_manager.setCellData(ds_manager.getRowPosition(), "eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
		ds_manager.setCellData(ds_manager.getRowPosition(), "ctrtEndDt", "99991231");
	}
};

scwin.f_AddClnt = async function (){
	if (ds_results.getRowCount() == 0){
		await $c.win.alert("차량정보가 없습니다. 신규버튼을 클릭하여 새로 등록하거나 조회하시기 바랍니다.");
	}else{
		if (ds_results.getCellData(ds_results.getRowPosition(), "clntNo") == ""){
			await $c.win.alert("차량정보 중 소속거래처 정보가 없습니다.");
			return false;
		}
		if (scwin.retrieveDetailYn == "notYet"){
            ds_clnt.removeAll();
		}else{
            var idx = ds_clnt.insertRow();
            ds_clnt.setRowPosition(idx);
		}

		ds_clnt.setCellData(ds_clnt.getRowPosition(), "selpchClsCd", "1"); // 매출거래처
		ds_clnt.setCellData(ds_clnt.getRowPosition(), "eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
		ds_clnt.setCellData(ds_clnt.getRowPosition(), "clntNo", ds_results.getCellData(ds_results.getRowPosition(), "clntNo"));
		ds_clnt.setCellData(ds_clnt.getRowPosition(), "clntNm", ds_results.getCellData(ds_results.getRowPosition(), "clntNm"));
		ds_clnt.setCellData(ds_clnt.getRowPosition(), "ctrtEndDt", "99991231");
	}
};

