scwin.sbm_retrieve_submit = function (e) {
    ds_condition.set("clntNo", ed_clntNo.getValue());
    ds_condition.set("vehclNo", ed_vehclNoNm.getValue());
    ds_condition.set("stDt", ica_stDt.getValue());
    ds_condition.set("endDt", ica_endDt.getValue());
