    ds_condition.set("managerCd", ed_managerCd.getValue());

};

scwin.sbm_retrieve_submitdone = async function (e) {
    var rowCnt = ds_results.getRowCount();
    txt_totalRows1.setValue(rowCnt);

    if (rowCnt == 0){
		await $c.win.alert("조회된 데이터가 없습니다.");
        // await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
		return false;
	}else{
        ds_results.setRowPosition(0);
		scwin.f_Retrieve_clntAndManager();
		$c.gus.cfDisableObjects([ed_prdyr, ed_vehclNo, ed_drcrNo, ed_degNm, ed_degForm, acb_eqNrmCd, ed_stdFleffcncy, ed_clntNo_rslts, ed_clntNm_rslts
