scwin.gr_clnt_oneditend = function (row, columnIndex, value) {
    var colid = gr_clnt.getColumnID(columnIndex);
    if (colid == "clntNm"){
		var clntNm = ds_clnt.getCellData(row, "clntNm");
		if (clntNm == ""){
			ds_clnt.setCellData(row, "clntNm", "");
			return;				
		}
		scwin.f_openCommonPopUp(4, '', clntNm, 'F', 'F',row);
	}
};

